render.css:
.holo-container { display: flex; align-items: center; justify-content: center; height: 180px; perspective: 600px; }
.holo-scene { transform-style: preserve-3d; position: relative; width: 120px; height: 120px; }
.holo-ring { position: absolute; border: 1px solid var(--ct-text-muted); border-radius: 50%; top: 50%; left: 50%; }
.ring-1 { width: 120px; height: 120px; margin: -60px 0 0 -60px; animation: holoSpin1 8s linear infinite; }
.ring-2 { width: 90px; height: 90px; margin: -45px 0 0 -45px; border-color: var(--ct-text-strong); animation: holoSpin2 6s linear infinite; }
.ring-3 { width: 60px; height: 60px; margin: -30px 0 0 -30px; animation: holoSpin3 4s linear infinite; }
.ring-core { width: 12px; height: 12px; margin: -6px 0 0 -6px; background: var(--ct-text-strong); border: none; box-shadow: 0 0 12px var(--ct-text-strong); animation: holoPulse 2s ease-in-out infinite; }
@keyframes holoSpin1 { from { transform: rotateX(60deg) rotateZ(0deg); } to { transform: rotateX(60deg) rotateZ(360deg); } }
@keyframes holoSpin2 { from { transform: rotateY(60deg) rotateZ(0deg); } to { transform: rotateY(60deg) rotateZ(360deg); } }
@keyframes holoSpin3 { from { transform: rotateX(60deg) rotateY(45deg) rotateZ(0deg); } to { transform: rotateX(60deg) rotateY(45deg) rotateZ(-360deg); } }
@keyframes holoPulse { 0%, 100% { transform: scale(1); opacity: 1; } 50% { transform: scale(1.5); opacity: 0.6; } }
